import{f as r,D as l,o as n,c as p,a2 as t,b as o,w as s,a as i,G as d,a5 as h}from"./chunks/framework.DHYrF-q6.js";const q=JSON.parse('{"title":"AI PM 工具链与工作流","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/tools-and-workflow.md","filePath":"ai-product-manager/tools-and-workflow.md","lastUpdated":1781090818000}'),u={name:"ai-product-manager/tools-and-workflow.md"};function c(b,a,m,g,A,P){const e=l("Mermaid");return n(),p("div",null,[a[1]||(a[1]=t('<h1 id="ai-pm-工具链与工作流" tabindex="-1">AI PM 工具链与工作流 <a class="header-anchor" href="#ai-pm-工具链与工作流" aria-label="Permalink to &quot;AI PM 工具链与工作流&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>知道方法论不够，你还需要知道<strong>打开电脑第一步做什么</strong>。本章从 Prompt 管理、实验追踪、数据标注、Agent 搭建、模型 API 调试五个维度，给出 AI PM 日常工作的工具选型和典型工作流。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>熟悉 AI PM 日常工作中使用的主流工具，能在面试中说出&quot;我用 xxx 工具解决 yyy 问题&quot;，而非&quot;理论上应该这样&quot;。</p></div><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',6)),(n(),o(h,null,{default:s(()=>[d(e,{id:"mermaid-18",class:"mermaid",graph:"mindmap%0A%20%20root((AI%20PM%20%E5%B7%A5%E5%85%B7%E9%93%BE))%0A%20%20%20%20Prompt%20%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%E7%89%88%E6%9C%AC%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20A%2FB%20%E6%B5%8B%E8%AF%95%0A%20%20%20%20%20%20%E6%95%88%E6%9E%9C%E8%BF%BD%E8%B8%AA%0A%20%20%20%20%20%20%E5%9B%A2%E9%98%9F%E5%8D%8F%E4%BD%9C%0A%20%20%20%20%E5%AE%9E%E9%AA%8C%E8%BF%BD%E8%B8%AA%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E5%AE%9E%E9%AA%8C%E8%AE%B0%E5%BD%95%0A%20%20%20%20%20%20%E6%8C%87%E6%A0%87%E5%AF%B9%E6%AF%94%0A%20%20%20%20%20%20%E8%B6%85%E5%8F%82%E6%95%B0%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%E5%AE%9E%E9%AA%8C%E5%A4%8D%E7%8E%B0%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E6%A0%87%E6%B3%A8%0A%20%20%20%20%20%20%E6%A0%87%E6%B3%A8%E9%A1%B9%E7%9B%AE%E9%85%8D%E7%BD%AE%0A%20%20%20%20%20%20%E8%B4%A8%E9%87%8F%E6%8E%A7%E5%88%B6%0A%20%20%20%20%20%20%E6%A0%87%E6%B3%A8%E5%9B%A2%E9%98%9F%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E5%AF%BC%E5%87%BA%0A%20%20%20%20Agent%20%E6%90%AD%E5%BB%BA%0A%20%20%20%20%20%20%E4%BD%8E%E4%BB%A3%E7%A0%81%20Agent%20%E5%B9%B3%E5%8F%B0%0A%20%20%20%20%20%20%E5%B7%A5%E4%BD%9C%E6%B5%81%E7%BC%96%E6%8E%92%0A%20%20%20%20%20%20%E7%9F%A5%E8%AF%86%E5%BA%93%E9%9B%86%E6%88%90%0A%20%20%20%20%20%20%E5%AF%B9%E8%AF%9D%E6%B5%8B%E8%AF%95%0A%20%20%20%20%E6%A8%A1%E5%9E%8B%20API%20%E8%B0%83%E8%AF%95%0A%20%20%20%20%20%20API%20%E8%B0%83%E7%94%A8%E6%B5%8B%E8%AF%95%0A%20%20%20%20%20%20%E5%8F%82%E6%95%B0%E8%B0%83%E6%95%B4%0A%20%20%20%20%20%20%E5%93%8D%E5%BA%94%E5%88%86%E6%9E%90%0A%20%20%20%20%20%20Token%20%E8%AE%A1%E6%95%B0%0A"})]),fallback:s(()=>[...a[0]||(a[0]=[i(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=t(`<hr><h2 id="二、prompt-管理与测试" tabindex="-1">二、Prompt 管理与测试 <a class="header-anchor" href="#二、prompt-管理与测试" aria-label="Permalink to &quot;二、Prompt 管理与测试&quot;">​</a></h2><h3 id="_2-1-为什么需要专门的-prompt-管理工具" tabindex="-1">2.1 为什么需要专门的 Prompt 管理工具？ <a class="header-anchor" href="#_2-1-为什么需要专门的-prompt-管理工具" aria-label="Permalink to &quot;2.1 为什么需要专门的 Prompt 管理工具？&quot;">​</a></h3><p>手动管理 Prompt 在初期勉强可行，但随着产品迭代，三个问题会越来越突出：</p><ul><li><strong>版本混乱</strong>：&quot;上周的 V3.2 比今天的 V3.3 好，但我不记得 V3.2 长什么样了&quot;</li><li><strong>协作困难</strong>：工程师改了 System Prompt 中的某一行，PM 不知道、没测试、直接上线——翻车</li><li><strong>效果无法追踪</strong>：改 Prompt 之后效果变了，但没有系统的 A/B 记录</li></ul><h3 id="_2-2-主流工具对比" tabindex="-1">2.2 主流工具对比 <a class="header-anchor" href="#_2-2-主流工具对比" aria-label="Permalink to &quot;2.2 主流工具对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>定位</th><th>核心功能</th><th>适合谁</th></tr></thead><tbody><tr><td><strong>LangSmith</strong></td><td>全链路 LLM 应用追踪</td><td>Prompt 版本管理、评测、线上追踪</td><td>团队协作、专业项目</td></tr><tr><td><strong>PromptLayer</strong></td><td>轻量级 Prompt 版本管理</td><td>版本对比、历史记录、API 代理</td><td>中小团队、快速启动</td></tr><tr><td><strong>OpenAI Playground</strong></td><td>官方调试工具</td><td>即时测试、参数调整、Token 计数</td><td>个人探索、快速验证</td></tr><tr><td><strong>Dify</strong></td><td>低代码 LLM 应用平台</td><td>可视化编排、Prompt 调试、知识库</td><td>PM 独立搭建 Demo</td></tr></tbody></table><h3 id="_2-3-典型工作流-prompt-迭代-6-步-sop" tabindex="-1">2.3 典型工作流：Prompt 迭代 6 步 SOP <a class="header-anchor" href="#_2-3-典型工作流-prompt-迭代-6-步-sop" aria-label="Permalink to &quot;2.3 典型工作流：Prompt 迭代 6 步 SOP&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 发现问题（线上 Bad Case 分析 or 人工评估发现）</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>2. 在 LangSmith 中拉取&quot;当前版本 Prompt&quot;</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>3. 创建新版本 V(N+1)，修改 Prompt</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>4. 在评测集上跑 VN vs V(N+1) 对比（LangSmith 的对比功能）</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>5. 如果 V(N+1) 整体更好且无退化 → 标记为 release candidate</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>6. 在 Playground 上做最终人工抽查 → 灰度上线</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><hr><h2 id="三、实验追踪" tabindex="-1">三、实验追踪 <a class="header-anchor" href="#三、实验追踪" aria-label="Permalink to &quot;三、实验追踪&quot;">​</a></h2><h3 id="_3-1-为什么-ai-pm-需要关注实验追踪" tabindex="-1">3.1 为什么 AI PM 需要关注实验追踪 <a class="header-anchor" href="#_3-1-为什么-ai-pm-需要关注实验追踪" aria-label="Permalink to &quot;3.1 为什么 AI PM 需要关注实验追踪&quot;">​</a></h3><p>当你跟算法团队开会时，他们说&quot;上周的实验用了 learning rate 0.001 的版本比 0.0001 好&quot;，你需要能够<strong>看懂并追问实验记录</strong>。这不是让你成为 MLE，而是让你能在关键时刻提出正确的问题。</p><h3 id="_3-2-主流工具" tabindex="-1">3.2 主流工具 <a class="header-anchor" href="#_3-2-主流工具" aria-label="Permalink to &quot;3.2 主流工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>特点</th><th>AI PM 需要知道的</th></tr></thead><tbody><tr><td><strong>Weights &amp; Biases</strong></td><td>业界标准、UI 优秀</td><td>能打开实验 Dashboard 看指标对比、Loss 曲线</td></tr><tr><td><strong>MLflow</strong></td><td>开源、可私有部署</td><td>了解基本的 experiment → run → artifact 层级</td></tr><tr><td><strong>TensorBoard</strong></td><td>Google 出品、免费</td><td>只看不操作，理解 Loss 下降趋势和过拟合判断</td></tr></tbody></table><h3 id="_3-3-pm-视角的实验追踪-checklist" tabindex="-1">3.3 PM 视角的实验追踪 Checklist <a class="header-anchor" href="#_3-3-pm-视角的实验追踪-checklist" aria-label="Permalink to &quot;3.3 PM 视角的实验追踪 Checklist&quot;">​</a></h3><p>不需要操作，但要能看能问：</p><ul><li>[ ] 这次实验改了哪些超参数？（learning rate / batch size / epoch）</li><li>[ ] 训练 Loss 和验证 Loss 的差距大吗？（差距 &gt; 10% 可能是过拟合）</li><li>[ ] 跟上一个 best model 对比了吗？（不能只看绝对值）</li><li>[ ] 实验目的是什么？验证什么假设？（不能&quot;调了看看&quot;）</li></ul><hr><h2 id="四、数据标注工具" tabindex="-1">四、数据标注工具 <a class="header-anchor" href="#四、数据标注工具" aria-label="Permalink to &quot;四、数据标注工具&quot;">​</a></h2><h3 id="_4-1-工具选型" tabindex="-1">4.1 工具选型 <a class="header-anchor" href="#_4-1-工具选型" aria-label="Permalink to &quot;4.1 工具选型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>适用场景</th><th>优势</th><th>不足</th></tr></thead><tbody><tr><td><strong>LabelStudio</strong></td><td>文本/图像/音频标注</td><td>开源免费、可自部署、支持多种标注模板</td><td>UI 略显复杂</td></tr><tr><td><strong>Labelbox</strong></td><td>大规模商业标注</td><td>标注团队管理、质量审核流程、API 集成</td><td>收费、有学习成本</td></tr><tr><td><strong>Doccano</strong></td><td>轻量级文本标注</td><td>极简、快速启动</td><td>功能较少</td></tr><tr><td><strong>GPT-4o API 辅助标注</strong></td><td>快速冷启动标注</td><td>速度和成本优势巨大</td><td>需要人工审核修正</td></tr></tbody></table><h3 id="_4-2-典型工作流-用-labelstudio-做情感分类标注" tabindex="-1">4.2 典型工作流：用 LabelStudio 做情感分类标注 <a class="header-anchor" href="#_4-2-典型工作流-用-labelstudio-做情感分类标注" aria-label="Permalink to &quot;4.2 典型工作流：用 LabelStudio 做情感分类标注&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: 在 LabelStudio 创建项目</span></span>
<span class="line"><span>  → 选择&quot;文本分类&quot;模板</span></span>
<span class="line"><span>  → 定义标签：正面/中性/负面</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 2: 导入待标注数据（JSON/CSV）</span></span>
<span class="line"><span>  → 上传 1000 条用户评论</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 3: 配置标注界面</span></span>
<span class="line"><span>  → 显示文本 + 单选标签按钮</span></span>
<span class="line"><span>  → 可选：加一个&quot;不确定&quot;按钮</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 4: 分配标注任务</span></span>
<span class="line"><span>  → 发给 2 个标注员（每人标全部 1000 条，用于算 Kappa）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 5: 质量审核</span></span>
<span class="line"><span>  → 导出标注结果 → Python 脚本算 Kappa 系数</span></span>
<span class="line"><span>  → Kappa &lt; 0.7 → 跟标注员开会讨论不一致的 Case → 修订标注规范 → 重新标注</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Step 6: 导出训练数据</span></span>
<span class="line"><span>  → 导出为 JSON → 清洗 → 划分 train/val/test → 送入训练 Pipeline</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><hr><h2 id="五、agent-搭建平台" tabindex="-1">五、Agent 搭建平台 <a class="header-anchor" href="#五、agent-搭建平台" aria-label="Permalink to &quot;五、Agent 搭建平台&quot;">​</a></h2><h3 id="_5-1-为什么-pm-需要自己搭-agent" tabindex="-1">5.1 为什么 PM 需要自己搭 Agent <a class="header-anchor" href="#_5-1-为什么-pm-需要自己搭-agent" aria-label="Permalink to &quot;5.1 为什么 PM 需要自己搭 Agent&quot;">​</a></h3><p>不需要你用代码实现一个 Agent——但你需要能<strong>在 2 小时内搭出一个可交互的 Demo</strong>。这在两个场景下至关重要：</p><ul><li><strong>快速验证想法</strong>：有个新想法想测试可行性——自己搭个 Demo 比写 20 页 PRD 有效得多</li><li><strong>跟工程师对齐需求</strong>：PM 用低代码平台搭出&quot;想要的样子&quot;，工程师知道你的预期——比纯文字描述准确 100 倍</li></ul><h3 id="_5-2-低代码-无代码-agent-平台对比" tabindex="-1">5.2 低代码/无代码 Agent 平台对比 <a class="header-anchor" href="#_5-2-低代码-无代码-agent-平台对比" aria-label="Permalink to &quot;5.2 低代码/无代码 Agent 平台对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>平台</th><th>定位</th><th>核心能力</th><th>上手难度</th></tr></thead><tbody><tr><td><strong>Dify</strong></td><td>开源 LLM 应用平台</td><td>工作流编排、RAG 知识库、Agent 模式、对话日志</td><td>★★☆</td></tr><tr><td><strong>Coze（扣子）</strong></td><td>字节跳动出品</td><td>插件市场、Bot 发布（微信/飞书）、知识库集成</td><td>★☆☆</td></tr><tr><td><strong>LangChain</strong></td><td>开发者框架</td><td>Python/JS SDK、完整的 Agent 工具链</td><td>★★★</td></tr><tr><td><strong>Flowise</strong></td><td>开源可视化编排</td><td>拖拽式工作流、支持多种 LLM</td><td>★★☆</td></tr></tbody></table><h3 id="_5-3-推荐入门路径" tabindex="-1">5.3 推荐入门路径 <a class="header-anchor" href="#_5-3-推荐入门路径" aria-label="Permalink to &quot;5.3 推荐入门路径&quot;">​</a></h3><ol><li>先用 <strong>Coze 或 Dify</strong> 搭一个最简单的 QA Bot（知识库 + 大模型）——1 小时搞定</li><li>加上工具调用（Function Call）——查询天气、搜索商品——练习 Agent 的核心模式</li><li>设计一个多步骤工作流（用户输入 → 意图识别 → 路由到不同处理 → 生成回答）</li><li>用对话日志功能分析 Bad Case，迭代 Prompt</li></ol><hr><h2 id="六、模型-api-调试" tabindex="-1">六、模型 API 调试 <a class="header-anchor" href="#六、模型-api-调试" aria-label="Permalink to &quot;六、模型 API 调试&quot;">​</a></h2><h3 id="_6-1-常用调试工具" tabindex="-1">6.1 常用调试工具 <a class="header-anchor" href="#_6-1-常用调试工具" aria-label="Permalink to &quot;6.1 常用调试工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>PM 必会程度</th></tr></thead><tbody><tr><td><strong>OpenAI Playground</strong></td><td>测试 Prompt、调整参数（temperature/top_p/max_tokens）</td><td>★★★★★</td></tr><tr><td><strong>Postman</strong></td><td>调用 API、查看原始 JSON 响应</td><td>★★★★☆</td></tr><tr><td><strong>Claude Console</strong></td><td>Anthropic 的官方调试台</td><td>★★★☆☆</td></tr><tr><td><strong>Hugging Face Playground</strong></td><td>测试开源模型</td><td>★★★☆☆</td></tr></tbody></table><h3 id="_6-2-openai-playground-实操-5-分钟上手" tabindex="-1">6.2 OpenAI Playground 实操 5 分钟上手 <a class="header-anchor" href="#_6-2-openai-playground-实操-5-分钟上手" aria-label="Permalink to &quot;6.2 OpenAI Playground 实操 5 分钟上手&quot;">​</a></h3><ol><li>打开 <code>platform.openai.com/playground</code></li><li>在 System 框写 System Prompt</li><li>在 User 框写测试用户输入</li><li>调整右侧参数： <ul><li><strong>Temperature</strong>（0-2）：控制随机性。0 = 每次都一样，1 = 有创意。<strong>客服/分类场景用 0-0.3，创意写作场景用 0.7-1</strong></li><li><strong>Max tokens</strong>：控制输出长度。客服回答一般 200-500 tokens 足够</li><li><strong>Top P</strong>：常用 0.9-1，一般不用动</li></ul></li><li>点击 Submit → 看结果 → 调 Prompt → 再试</li><li>满意的 Prompt 直接&quot;View code&quot;导出为 Python/Node.js 代码发给工程师</li></ol><h3 id="_6-3-一个完整的调试循环示例" tabindex="-1">6.3 一个完整的调试循环示例 <a class="header-anchor" href="#_6-3-一个完整的调试循环示例" aria-label="Permalink to &quot;6.3 一个完整的调试循环示例&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>假设你在做一个&quot;商品评价总结&quot;功能：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 在 Playground 写 Prompt：</span></span>
<span class="line"><span>   &quot;你是一个电商评价分析助手。请对以下用户评价做一句话总结，</span></span>
<span class="line"><span>    并标注情感（正面/中性/负面）。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 输入测试：&quot;物流挺快的，但是包装有点简陋，商品本身还不错&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 看结果 → 模型输出&quot;用户对物流和商品满意，但对包装不满意，整体偏正面&quot;</span></span>
<span class="line"><span>   → 问题：你需要的是&quot;一句话总结&quot;，这个太长了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 调 Prompt：加&quot;总结不超过 15 个字&quot;</span></span>
<span class="line"><span>   → 新结果&quot;物流快包装简，商品好&quot;→ 太省略了，信息丢失</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 再调：加&quot;总结 15-30 字，必须包含用户提到的所有方面&quot;</span></span>
<span class="line"><span>   → 新结果&quot;物流快但包装简陋，商品本身满意，整体好评&quot;</span></span>
<span class="line"><span>   → ✅ 这版可以</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 导出 Prompt + 参数配置 → 交付给工程师</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><hr><h2 id="七、面试追问合集" tabindex="-1">七、面试追问合集 <a class="header-anchor" href="#七、面试追问合集" aria-label="Permalink to &quot;七、面试追问合集&quot;">​</a></h2><h3 id="q1-你日常用什么工具管理-prompt-流程是怎样的" tabindex="-1">Q1: 你日常用什么工具管理 Prompt？流程是怎样的？ <a class="header-anchor" href="#q1-你日常用什么工具管理-prompt-流程是怎样的" aria-label="Permalink to &quot;Q1: 你日常用什么工具管理 Prompt？流程是怎样的？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>我们用 LangSmith 管理 Prompt 的版本和评测。具体流程是：</p><ol><li>所有 Prompt 都在 LangSmith 上有版本记录——从 V1 到当前版本的完整历史</li><li>每次修改 Prompt 都要附上&quot;修改原因&quot;和&quot;预期的改进方向&quot;——这是 PM 写的</li><li>对比评测：新版本在 200 条评测集上跑一遍，跟当前版本做对比——确认整体提升且无退化</li><li>PM 在 Playground 上做 10-20 条人工抽查（尤其是边界 Case），通过后标记为 release candidate</li><li>工程师拿到 PM 确认后的 Prompt 进行灰度上线</li></ol><p>这个流程的关键是<strong>PM 对 Prompt 质量负责，工程师对系统稳定性负责</strong>——分工明确、互不甩锅。</p></details><h3 id="q2-你对-prompt-自动化优化-dspy-等-怎么看-pm-需要学吗" tabindex="-1">Q2: 你对 Prompt 自动化优化（DSPy 等）怎么看？PM 需要学吗？ <a class="header-anchor" href="#q2-你对-prompt-自动化优化-dspy-等-怎么看-pm-需要学吗" aria-label="Permalink to &quot;Q2: 你对 Prompt 自动化优化（DSPy 等）怎么看？PM 需要学吗？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>DSPy 的思路是&quot;用编程方式自动优化 Prompt&quot;——你定义评估指标，它自动生成和调优 Prompt。这是未来趋势，但现阶段 PM 需要的是一个务实的判断：</p><p><strong>短期（1-2 年）</strong>：手工调 Prompt 仍然是主流。DSPy 适合&quot;有明确的自动化评估指标&quot;的场景（如分类准确率），但很多产品场景的评估指标本身就是模糊的（&quot;回答是否友好&quot;——这怎么自动化打分？）。</p><p><strong>长期</strong>：PM 需要理解 DSPy 的思路——<strong>从&quot;手写 Prompt&quot;到&quot;用评估指标驱动 Prompt 优化&quot;</strong>。这跟传统 PM 从&quot;手画原型&quot;到&quot;用数据驱动设计&quot;的演变本质相同。</p><p><strong>我建议 PM 做什么</strong>：了解 DSPy 的基本概念和适用边界，但不必花大量时间学。更值得投资的是<strong>把自己的评估体系做到位</strong>——因为无论是手工调 Prompt 还是 DSPy 自动调，都需要一个可靠评估体系来判断&quot;调好了没有&quot;。评估体系是基础，优化方法是上层。</p></details><h3 id="q3-如果你们的-dify-平台突然不可用-你有什么备选方案" tabindex="-1">Q3: 如果你们的 Dify 平台突然不可用，你有什么备选方案？ <a class="header-anchor" href="#q3-如果你们的-dify-平台突然不可用-你有什么备选方案" aria-label="Permalink to &quot;Q3: 如果你们的 Dify 平台突然不可用，你有什么备选方案？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>AI PM 需要对自己依赖的平台有<strong>单点故障的认知和预案</strong>。</p><ol><li><p><strong>Prompt 备份</strong>：所有 System Prompt 和模板都在 Git 仓库里有备份——不只是 Dify 平台上的那份。Dify 挂了，Prompt 不会丢。</p></li><li><p><strong>API 直连方式</strong>：在 Dify 之外，我们用 LangSmith 的 API 代理层来调用模型——这意味着如果 Dify 挂了，我们可以绕过它直接用 API 调用 GPT-4o。虽然少了工作流编排，但核心功能（问答）不会中断。</p></li><li><p><strong>知识库备份</strong>：RAG 知识库的原始文档也存储在内部 Wiki（Confluence/飞书文档），确保检索源不会丢失。</p></li></ol><p>这不是过度设计——我们真的遇到过某低代码平台突然改了定价策略导致成本翻倍的情况。<strong>依赖外部平台的同时保持可迁移性</strong>，是 AI PM 的风险管理基本功。</p></details><hr><h2 id="推荐上手路线" tabindex="-1">推荐上手路线 <a class="header-anchor" href="#推荐上手路线" aria-label="Permalink to &quot;推荐上手路线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>周次</th><th>学习内容</th><th>产出物</th></tr></thead><tbody><tr><td>第 1 周</td><td>OpenAI Playground 调试 10+ 个不同 Prompt</td><td>5 个自己写的 Prompt 模板</td></tr><tr><td>第 2 周</td><td>用 Dify 搭一个客服 QA Bot（有知识库）</td><td>可演示的 Demo</td></tr><tr><td>第 3 周</td><td>用 LabelStudio 做一个小型标注项目（50 条）</td><td>标注规范 + 导出数据</td></tr><tr><td>第 4 周</td><td>用 LangSmith 管理 Prompt 版本和评测</td><td>一个完整的 Prompt 迭代记录</td></tr></tbody></table><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./prompt-engineering">Prompt 工程</a></li><li><a href="./evaluation">AI 评估体系</a></li><li><a href="./case-study">实战案例：智能客服全流程</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>`,55))])}const B=r(u,[["render",c]]);export{q as __pageData,B as default};
